import { getUserInfo } from '@/api/user'

export default {
  namespaced: true,
  state: {
    userInfo: null
  },
  mutations: {
    SET_USER(state, info) {
      state.userInfo = info
    }
  },
  actions: {
    async fetchUserInfo({ commit }) {
      const res = await getUserInfo()
      commit('SET_USER', res.data)
    }
  }
}